mapper.select:
SELECT CONCAT(CONVERT(varchar(10), a.pur_date, 23), ' - ', a.seq) AS purDateSeq , dbo.getCustomerName(a.customer_cd) AS customer_name , CASE WHEN x.item_cnt = 1 THEN x.first_item_name ELSE x.first_item_name + ' 외 ' + CAST(x.item_cnt - 1 AS varchar) + '건' END AS item_name , x.totQty , x.totPrice , dbo.getStorageName(a.storage_cd) AS storage_name , a.order_type , dbo.getUserName(a.manager_id) AS manager_name , a.erp_yn , a.pur_id FROM tb_pur_mst a INNER JOIN ( SELECT b.pur_id , COUNT(b.pur_item_id) AS item_cnt , SUM(ISNULL(b.qty, 0)) AS totQty , SUM(ISNULL(b.supply_price, 0) - ISNULL(b.vat_price, 0)) AS totPrice , ( SELECT TOP 1 b2.item_name FROM tb_pur_item b2 WHERE b2.pur_id = b.pur_id ORDER BY b2.pur_item_id ) AS first_item_name FROM tb_pur_item b GROUP BY b.pur_id ) x ON a.pur_id = x.pur_id WHERE a.pur_date BETWEEN #{strDate} AND #{toDate}
AND a.area_cd = #{areaCd}
AND a.end_yn = #{endYn}
AND dbo.getCustomerName(a.customer_cd) LIKE '%' + #{customerName} + '%'
AND EXISTS ( SELECT 1 FROM tb_pur_item i WHERE i.pur_id = a.pur_id AND i.item_name LIKE '%' + #{itemName} + '%' )
AND EXISTS ( SELECT 1 FROM tb_pur_item i WHERE i.pur_id = a.pur_id AND i.item_cd LIKE '%' + #{itemCd} + '%' )
AND EXISTS ( SELECT 1 FROM tb_pur_item i WHERE i.pur_id = a.pur_id AND i.item_type_cd = #{itemTypeCd} )
ORDER BY a.pur_date DESC, a.seq DESC

mapper.insert:
INSERT INTO dbo.tb_pur_mst (
    pur_date, seq, area_cd, storage_cd, customer_cd, manager_id, remark, order_type, vat_type, reg_id, upd_id
)
VALUES (
    #{purDate}, #{seq}, #{areaCd}, #{storageCd}, #{customerCd},#{managerId}, #{remark}, #{orderType}, #{vatType}, #{userId}, #{userId}
       )

mapper.update:
UPDATE dbo.tb_pur_mst
SET    pur_date   = #{purDate}
      ,seq        = #{seq}
      ,area_cd    = #{areaCd}
      ,storage_cd = #{storageCd}
      ,customer_cd= #{customerCd}
      ,manager_id = #{managerId}
      ,remark     = #{remark}
      ,order_type = #{orderType}
      ,vat_type   = #{vatType}
      ,upd_id     = #{userId}
      ,upd_dt     = GETDATE()
WHERE  pur_id     = #{purId}

UPDATE  tb_pur_item
SET      spec         = #{spec}
        ,qty          = #{qty}
        ,supply_price = #{supplyPrice}
        ,vat_price    = #{vatPrice}
        ,lot_no       = #{lotNo}
        ,expiry_date  = #{expiryDate}
        ,etc          = #{etc}
        ,upd_id       = #{userId}
        ,upd_dt       = GETDATE()
WHERE pur_item_id  = #{purItemId}

